  {id: 407, name: "sydparse", url: "https://rubygems.org/gems/sydparse", description: "A standalone ruby parser with sexp support."},
  {id: 408, name: "systemu", url: "https://github.com/ahoward/systemu", description: "universal capture of stdout and stderr and handling of child process pid for windows, *nix, etc."},
  {id: 409, name: "tagz", url: "https://github.com/ahoward/tagz", description: "\n        tagz.rb is generates html, xml, or any sgml variant like a small ninja\n        running across the backs of a herd of giraffes swatting of heads like\n        a mark-up weedwacker.  weighing in at less than 300 lines of code\n        tagz.rb adds an html/xml/sgml syntax to ruby that is both unobtrusive,\n        safe, and available globally to objects without the need for any\n        builder or superfluous objects.  tagz.rb is designed for applications\n        that generate html to be able to do so easily in any context without\n        heavyweight syntax or scoping issues, like a ninja sword through\n        butter.\n\n"},
  {id: 410, name: "taka", url: "https://rubygems.org/gems/taka", description: "Taka is a DOM (core and html) implementation for ruby.  This software is EXTREMELY experimental.  You may hurt yourself while using it."},
