  {id: 429, name: "versionomy", url: "https://rubygems.org/gems/versionomy", description: "Versionomy is a generalized version number library. It provides tools to represent, manipulate, parse, and compare version numbers in the wide variety of versioning schemes in use."},
  {id: 430, name: "vlad-hg", url: "https://rubygems.org/gems/vlad-hg", description: "Mercurial support for Vlad. Using it is as simple as passing\n<tt>:scm => :mercurial</tt> to Vlad when loading it up."},
  {id: 431, name: "vlad-merb", url: "https://rubygems.org/gems/vlad-merb", description: "Merb support for Vlad. Prior to 2.0.0, Vlad included support to make vlad:start\nand vlad:stop work with Merb; this plugin adds Merb support back in, and makes\nit a bit more robust."},
  {id: 432, name: "vlad-perforce", url: "https://rubygems.org/gems/vlad-perforce", description: "Vlad plugin providing perforce support. This was previously available\nin vlad but all extra modules outside of the core recipe have been\nremoved."},
